package test;

import com.puppycrawl.tools.checkstyle.*;
import com.puppycrawl.tools.checkstyle.api.*;
import com.puppycrawl.tools.checkstyle.checks.indentation.IndentationCheck;
import java.io.File;
import java.util.*;

public class TestBrace {
    public static void main(String[] args) throws Exception {
        // Create config
        DefaultConfiguration checkConfig = new DefaultConfiguration("Indentation");
        checkConfig.addProperty("braceAdjustment", "2");

        DefaultConfiguration treeWalkerConfig = new DefaultConfiguration("TreeWalker");
        treeWalkerConfig.addChild(checkConfig);

        DefaultConfiguration checkerConfig = new DefaultConfiguration("Checker");
        checkerConfig.addChild(treeWalkerConfig);

        Checker checker = new Checker();
        checker.setModuleClassLoader(Thread.currentThread().getContextClassLoader());
        checker.configure(checkerConfig);

        List<File> files = new ArrayList<>();
        files.add(new File("/tmp/TestBraceAdjustment.java"));

        List<String> violations = new ArrayList<>();
        checker.addListener(new AuditListener() {
            public void auditStarted(AuditEvent e) {}
            public void auditFinished(AuditEvent e) {}
            public void fileStarted(AuditEvent e) {}
            public void fileFinished(AuditEvent e) {}
            public void addError(AuditEvent e) {
                violations.add(e.getLine() + ": " + e.getMessage());
            }
            public void addException(AuditEvent e, Throwable t) {
                System.out.println("Exception: " + t.getMessage());
            }
        });

        int result = checker.process(files);
        checker.destroy();

        if (violations.isEmpty()) {
            System.out.println("No violations found!");
        } else {
            System.out.println("Violations:");
            for (String v : violations) {
                System.out.println("  " + v);
            }
        }
    }
}
